import re
from typing import Optional

class StringProcessor:
    """A utility class for advanced string manipulations."""

    def reverse_words(self, s: str) -> str:
        """Reverses the order of words in a string."""
        return " ".join(s.split()[::-1])

    def count_vowels(self, s: str) -> int:
        """Counts vowels (a, e, i, o, u) case-insensitively."""
        vowels = "aeiouAEIOU"
        return sum(1 for char in s if char in vowels)

    def is_palindrome(self, s: str) -> bool:
        """Checks if a string is a palindrome, ignoring case, spaces, and punctuation."""
        clean_s = "".join(char.lower() for char in s if char.isalnum())
        return clean_s == clean_s[::-1]

    def caesar_cipher(self, s: str, shift: int) -> str:
        """
        Shifts letters a-z and A-Z by the given shift value. 
        Non-alphabetic characters remain unchanged. Supports negative shifts.
        """
        result = []
        for char in s:
            if char.isalpha():
                start = ord('A') if char.isupper() else ord('a')
                # Use modulo 26 to handle overflow and negative shifts
                shifted = (ord(char) - start + shift) % 26
                result.append(chr(start + shifted))
            else:
                result.append(char)
        return "".join(result)

    def most_common_word(self, s: str) -> Optional[str]:
        """
        Returns the most frequent word (case-insensitive). 
        Returns the first word encountered in case of a tie.
        """
        if not s.strip():
            return None

        # Remove punctuation and split into lowercase words
        words = re.findall(r'\w+', s.lower())
        if not words:
            return None

        counts = {}
        for word in words:
            counts[word] = counts.get(word, 0) + 1

        # max() in Python is stable, so it returns the first occurrence in case of ties
        return max(words, key=lambda w: counts[w])

# --- Pytest Tests ---
import pytest

def test_reverse_words():
    sp = StringProcessor()
    assert sp.reverse_words("Hello World Python") == "Python World Hello"

def test_count_vowels():
    sp = StringProcessor()
    assert sp.count_vowels("Apple Pie") == 4  # A, e, i, e

def test_is_palindrome():
    sp = StringProcessor()
    assert sp.is_palindrome("A man, a plan, a canal: Panama") is True
    assert sp.is_palindrome("Hello") is False

def test_caesar_cipher():
    sp = StringProcessor()
    assert sp.caesar_cipher("abc XYZ", 1) == "bcd YZA"
    assert sp.caesar_cipher("bcd YZA", -1) == "abc XYZ"

def test_most_common_word():
    sp = StringProcessor()
    assert sp.most_common_word("The cat and the dog") == "the"
    assert sp.most_common_word("Apple Banana Apple Banana") == "apple"
    assert sp.most_common_word("") is None
```

### How to run the tests:
1. Save the code to a file named `string_processor.py`.
2. Install pytest: `pip install pytest`.
3. Run the tests using the command: `pytest string_processor.py`.
